class Solution {
    public int[] gardenNoAdj(int n, int[][] paths) {
        int[] answer = new int[n];
        boolean[][] graph = new boolean[n][n];

        for (int[] path : paths) {
            graph[path[0] - 1][path[1] - 1] = true;
            graph[path[1] - 1][path[0] - 1] = true;
        }

        for (int i = 0; i < n; i++) {
            boolean[] used = new boolean[5];
            for (int j = 0; j < n; j++) {
                if (graph[i][j] && answer[j] != 0) {
                    used[answer[j]] = true;
                }
            }
            for (int j = 1; j <= 4; j++) {
                if (!used[j]) {
                    answer[i] = j;
                    break;
                }
            }
        }

        return answer;
    }
}
